export function createModelSignal<T>(initialValue: T, opts?: ModelOptions): ModelSignal<T> {
  const node: InputSignalNode<T, T> = Object.create(INPUT_SIGNAL_NODE);
  const emitterRef = new OutputEmitterRef<T>();

  node.value = initialValue;

  function getter(): T {
    producerAccessed(node);
    assertModelSet(node.value);
    return node.value;
  }

  getter[SIGNAL] = node;
  getter.asReadonly = signalAsReadonlyFn.bind(getter as any) as () => Signal<T>;

  // TODO: Should we throw an error when updating a destroyed model?
  getter.set = (newValue: T) => {
    if (!node.equal(node.value, newValue)) {
      signalSetFn(node, newValue);
      emitterRef.emit(newValue);
    }
  };

  getter.update = (updateFn: (value: T) => T) => {
    assertModelSet(node.value);
    getter.set(updateFn(node.value));
  };

  getter.subscribe = emitterRef.subscribe.bind(emitterRef);
  getter.destroyRef = emitterRef.destroyRef;

  if (ngDevMode) {
    getter.toString = () => `[Model Signal: ${getter()}]`;
    node.debugName = opts?.debugName;
  }

  return getter as typeof getter &
    Pick<
      ModelSignal<T>,
      | typeof ɵINPUT_SIGNAL_BRAND_READ_TYPE
      | typeof ɵINPUT_SIGNAL_BRAND_WRITE_TYPE
      | typeof ɵWRITABLE_SIGNAL
    >;
}

() => {
  const month = this.viewMonth();

  const daysInMonth = this._dateAdapter.getNumDaysInMonth(month);
  const dateNames = this._dateAdapter.getDateNames();

  const calendar: CalendarCell[][] = [[]];
  for (let i = 0, cell = this._firstWeekOffset(); i < daysInMonth; i++, cell++) {
    if (cell == DAYS_PER_WEEK) {
      calendar.push([]);
      cell = 0;
    }
    const date = this._dateAdapter.createDate(
      this._dateAdapter.getYear(month),
      this._dateAdapter.getMonth(month),
      i + 1,
    );
    const ariaLabel = this._dateAdapter.format(date, this._dateFormats.display.dateA11yLabel);

    calendar[calendar.length - 1].push({
      displayName: dateNames[i],
      ariaLabel,
      date,
      selected: signal(
        this._dateAdapter.compareDate(
          date,
          untracked(() => this.selectedDate()),
        ) === 0,
      ),
      day: i + 1,
    });
  }

  return calendar;
}

buildKeyframes(): AnimationTimelineInstruction {
  this.applyStylesToKeyframe();
  const preStyleProps = new Set<string>();
  const postStyleProps = new Set<string>();
  const isEmpty = this._keyframes.size === 1 && this.duration === 0;

  let finalKeyframes: Array<ɵStyleDataMap> = [];
  this._keyframes.forEach((keyframe, time) => {
    const finalKeyframe = new Map([...this._backFill, ...keyframe]);
    finalKeyframe.forEach((value, prop) => {
      if (value === PRE_STYLE) {
        preStyleProps.add(prop);
      } else if (value === AUTO_STYLE) {
        postStyleProps.add(prop);
      }
    });
    if (!isEmpty) {
      finalKeyframe.set('offset', time / this.duration);
    }
    finalKeyframes.push(finalKeyframe);
  });

  const preProps: string[] = [...preStyleProps.values()];
  const postProps: string[] = [...postStyleProps.values()];

  // special case for a 0-second animation (which is designed just to place styles onscreen)
  if (isEmpty) {
    const kf0 = finalKeyframes[0];
    const kf1 = new Map(kf0);
    kf0.set('offset', 0);
    kf1.set('offset', 1);
    finalKeyframes = [kf0, kf1];
  }

  return createTimelineInstruction(
    this.element,
    finalKeyframes,
    preProps,
    postProps,
    this.duration,
    this.startTime,
    this.easing,
    false,
  );
}

gameLoop() {
  const keys = this.pressedKeys();
  if (!this.isDialogOpen()) {
    const currentPos = this.characterPosition();
    let newPos = {...currentPos};
    let moveDirection: 'horizontal' | 'vertical' | null = null;

    if (keys.has('ArrowUp')) {
      newPos.y -= MOVE_STEP;
      moveDirection = 'vertical';
      this.walkingDirection.set('up');
    } else if (keys.has('ArrowDown')) {
      newPos.y += MOVE_STEP;
      moveDirection = 'vertical';
      this.walkingDirection.set('down');
    } else if (keys.has('ArrowLeft')) {
      newPos.x -= MOVE_STEP;
      moveDirection = 'horizontal';
      this.walkingDirection.set('left');
    } else if (keys.has('ArrowRight')) {
      newPos.x += MOVE_STEP;
      moveDirection = 'horizontal';
      this.walkingDirection.set('right');
    } else {
      this.walkingDirection.set(null);
    }

    if (moveDirection && this.isMoveAllowed(currentPos, newPos, moveDirection)) {
      this.characterPosition.set(newPos);
      this.walkFrame.update((frame) => frame + 1);
    }
  }

  requestAnimationFrame(() => this.gameLoop());
}

ngOnChanges(changes: SimpleChanges<NgOptimizedImage>) {
  if (ngDevMode) {
    assertNoPostInitInputChange(this, changes, [
      'ngSrcset',
      'width',
      'height',
      'priority',
      'fill',
      'loading',
      'sizes',
      'loaderParams',
      'disableOptimizedSrcset',
    ]);
  }
  if (changes['ngSrc'] && !changes['ngSrc'].isFirstChange()) {
    const oldSrc = this._renderedSrc;
    this.updateSrcAndSrcset(true);

    if (ngDevMode) {
      const newSrc = this._renderedSrc;
      if (oldSrc && newSrc && oldSrc !== newSrc) {
        const ngZone = this.injector.get(NgZone);
        ngZone.runOutsideAngular(() => {
          this.lcpObserver!.updateImage(oldSrc, newSrc);
        });
      }
    }
  }

  if (
    ngDevMode &&
    changes['placeholder']?.currentValue &&
    typeof ngServerMode !== 'undefined' &&
    !ngServerMode
  ) {
    assertPlaceholderDimensions(this, this.imgElement);
  }
}

export function withState<State extends object>(
  stateOrFactory: State | (() => State)
): SignalStoreFeature<
  SignalStoreFeatureResult,
  { state: State; props: {}; methods: {} }
> {
  return (store) => {
    const state = (
      typeof stateOrFactory === 'function' ? stateOrFactory() : stateOrFactory
    ) as Record<string | symbol, unknown>;
    const stateKeys = Reflect.ownKeys(state);

    if (typeof ngDevMode !== 'undefined' && ngDevMode) {
      assertUniqueStoreMembers(store, stateKeys);
    }

    const stateSource = store[STATE_SOURCE] as Record<
      string | symbol,
      Signal<unknown>
    >;
    const stateSignals: SignalsDictionary = {};

    for (const key of stateKeys) {
      stateSource[key] = signal(state[key]);
      stateSignals[key] = toDeepSignal(stateSource[key]);
    }

    return {
      ...store,
      stateSignals: { ...store.stateSignals, ...stateSignals },
    } as InnerSignalStore<State>;
  };
}

export function withComputed<
  Input extends SignalStoreFeatureResult,
  ComputedDictionary extends Record<
    string | symbol,
    Signal<unknown> | (() => unknown)
  >,
>(
  computedFactory: (
    store: Prettify<
      StateSignals<Input['state']> & Input['props'] & Input['methods']
    >
  ) => ComputedDictionary
): SignalStoreFeature<
  Input,
  { state: {}; props: ComputedResult<ComputedDictionary>; methods: {} }
> {
  return withProps((store) => {
    const computedResult = computedFactory(store);
    const computedResultKeys = Reflect.ownKeys(computedResult);

    return computedResultKeys.reduce((prev, key) => {
      const signalOrComputation = computedResult[key];
      return {
        ...prev,
        [key]: isSignal(signalOrComputation)
          ? signalOrComputation
          : computed(signalOrComputation),
      };
    }, {} as ComputedResult<ComputedDictionary>);
  });
}

export function withHooks<Input extends SignalStoreFeatureResult>(
  hooksOrFactory:
    | {
        onInit?: HookFn<Input>;
        onDestroy?: HookFn<Input>;
      }
    | HooksFactory<Input>
): SignalStoreFeature<Input, EmptyFeatureResult> {
  return (store) => {
    const storeMembers = {
      [STATE_SOURCE]: store[STATE_SOURCE],
      ...store.stateSignals,
      ...store.props,
      ...store.methods,
    };
    const hooks =
      typeof hooksOrFactory === 'function'
        ? hooksOrFactory(storeMembers)
        : hooksOrFactory;
    const mergeHooks = (currentHook?: () => void, hook?: HookFn<Input>) => {
      return hook
        ? () => {
            if (currentHook) {
              currentHook();
            }

            hook(storeMembers);
          }
        : currentHook;
    };

    return {
      ...store,
      hooks: {
        onInit: mergeHooks(store.hooks.onInit, hooks.onInit),
        onDestroy: mergeHooks(store.hooks.onDestroy, hooks.onDestroy),
      },
    };
  };
}

export function createNgModuleType(meta: R3NgModuleMetadata): o.ExpressionType {
  if (meta.kind === R3NgModuleMetadataKind.Local) {
    return new o.ExpressionType(meta.type.value);
  }

  if (meta.kind === R3NgModuleMetadataKind.Isolated) {
    return new o.ExpressionType(
      o.importExpr(R3.NgModuleDeclaration, [
        new o.ExpressionType(meta.type.type),
        o.NONE_TYPE,
        meta.importsExpression ? o.expressionType(meta.importsExpression) : o.NONE_TYPE,
        meta.exportsExpression ? o.expressionType(meta.exportsExpression) : o.NONE_TYPE,
      ]),
    );
  }

  const {
    type: moduleType,
    declarations,
    exports,
    imports,
    includeImportTypes,
    publicDeclarationTypes,
  } = meta;

  return new o.ExpressionType(
    o.importExpr(R3.NgModuleDeclaration, [
      new o.ExpressionType(moduleType.type),
      publicDeclarationTypes === null
        ? tupleTypeOf(declarations)
        : tupleOfTypes(publicDeclarationTypes),
      includeImportTypes ? tupleTypeOf(imports) : o.NONE_TYPE,
      tupleTypeOf(exports),
    ]),
  );
}

export function toR3InjectableMeta<TExpression>(
  metaObj: AstObject<R3DeclareInjectableMetadata, TExpression>,
): R3InjectableMetadata {
  const typeExpr = metaObj.getValue('type');
  const typeName = typeExpr.getSymbolName();
  if (typeName === null) {
    throw new FatalLinkerError(
      typeExpr.expression,
      'Unsupported type, its name could not be determined',
    );
  }

  const meta: R3InjectableMetadata = {
    name: typeName,
    type: wrapReference(typeExpr.getOpaque()),
    typeArgumentCount: 0,
    providedIn: metaObj.has('providedIn')
      ? extractForwardRef(metaObj.getValue('providedIn'))
      : createMayBeForwardRefExpression(o.literal(null), ForwardRefHandling.None),
  };

  if (metaObj.has('useClass')) {
    meta.useClass = extractForwardRef(metaObj.getValue('useClass'));
  }
  if (metaObj.has('useFactory')) {
    meta.useFactory = metaObj.getOpaque('useFactory');
  }
  if (metaObj.has('useExisting')) {
    meta.useExisting = extractForwardRef(metaObj.getValue('useExisting'));
  }
  if (metaObj.has('useValue')) {
    meta.useValue = extractForwardRef(metaObj.getValue('useValue'));
  }

  if (metaObj.has('deps')) {
    meta.deps = metaObj.getArray('deps').map((dep) => getDependency(dep.getObject()));
  }

  return meta;
}

export function isAngularCorePackage(program: ts.Program): boolean {
  // Look for its_just_angular.ts somewhere in the program.
  const r3Symbols = getR3SymbolsFile(program);
  if (r3Symbols === null) {
    return false;
  }

  // Look for the constant ITS_JUST_ANGULAR in that file.
  return r3Symbols.statements.some((stmt) => {
    // The statement must be a variable declaration statement.
    if (!ts.isVariableStatement(stmt)) {
      return false;
    }
    // It must be exported.
    const modifiers = ts.getModifiers(stmt);
    if (
      modifiers === undefined ||
      !modifiers.some((mod) => mod.kind === ts.SyntaxKind.ExportKeyword)
    ) {
      return false;
    }
    // It must declare ITS_JUST_ANGULAR.
    return stmt.declarationList.declarations.some((decl) => {
      // The declaration must match the name.
      if (!ts.isIdentifier(decl.name) || decl.name.text !== 'ITS_JUST_ANGULAR') {
        return false;
      }
      // It must initialize the variable to true.
      if (decl.initializer === undefined || decl.initializer.kind !== ts.SyntaxKind.TrueKeyword) {
        return false;
      }
      // This definition matches.
      return true;
    });
  });
}

function generateValidGrid(
  rowCount: number,
  colCount: number,
  randomRowSpan: boolean = true,
  randomColSpan: boolean = true,
  randomDisable: boolean = true,
): Cell[][] {
  const grid: Cell[][] = [];
  const visitedCoords = new Set<string>();
  for (let r = 0; r < rowCount; r++) {
    const row = [];
    for (let c = 0; c < colCount; c++) {
      if (visitedCoords.has(`${r},${c}`)) {
        continue;
      }

      const rowSpan = randomRowSpan ? Math.min(randomSpan(), rowCount - r) : 1;
      const maxColSpan = randomColSpan ? Math.min(randomSpan(), colCount - c) : 1;
      let colSpan = 1;
      while (colSpan < maxColSpan) {
        if (visitedCoords.has(`${r},${c + colSpan}`)) break;
        colSpan += 1;
      }
      const disabled = randomDisable ? randomDisabled() : false;

      row.push({
        rowSpan,
        colSpan,
        disabled,
      });

      for (let rs = 0; rs < rowSpan; rs++) {
        for (let cs = 0; cs < colSpan; cs++) {
          visitedCoords.add(`${r + rs},${c + cs}`);
        }
      }
    }
    grid.push(row);
  }
  return grid;
}

function toHostMetadata<TExpression>(
  metaObj: AstObject<R3DeclareDirectiveMetadata, TExpression>,
): R3HostMetadata {
  if (!metaObj.has('host')) {
    return {
      attributes: {},
      listeners: {},
      properties: {},
      specialAttributes: {},
    };
  }

  const host = metaObj.getObject('host');

  const specialAttributes: R3HostMetadata['specialAttributes'] = {};
  if (host.has('styleAttribute')) {
    specialAttributes.styleAttr = host.getString('styleAttribute');
  }
  if (host.has('classAttribute')) {
    specialAttributes.classAttr = host.getString('classAttribute');
  }

  return {
    attributes: host.has('attributes')
      ? host.getObject('attributes').toLiteral((value) => value.getOpaque())
      : {},
    listeners: host.has('listeners')
      ? host.getObject('listeners').toLiteral((value) => value.getString())
      : {},
    properties: host.has('properties')
      ? host.getObject('properties').toLiteral((value) => value.getString())
      : {},
    specialAttributes,
  };
}

() => {
  const manager = new ClickEventManager<PointerEvent>();

  if (this.readonly()) {
    return manager.on(e => this.listBehavior.goto(this._getItem(e)!));
  }

  if (this.multi()) {
    manager.on(Modifier.Shift, e =>
      this.listBehavior.goto(this._getItem(e)!, {selectRange: true}),
    );
  }

  if (!this.multi() && this.followFocus()) {
    return manager.on(e => this.listBehavior.goto(this._getItem(e)!, {selectOne: true}));
  }

  if (!this.multi() && !this.followFocus()) {
    return manager.on(e => this.listBehavior.goto(this._getItem(e)!, {toggle: true}));
  }

  if (this.multi() && this.followFocus()) {
    return manager
      .on(e => this.listBehavior.goto(this._getItem(e)!, {selectOne: true}))
      .on(Modifier.Ctrl, e => this.listBehavior.goto(this._getItem(e)!, {toggle: true}));
  }

  if (this.multi() && !this.followFocus()) {
    return manager.on(e => this.listBehavior.goto(this._getItem(e)!, {toggle: true}));
  }

  return manager;
}

export const ngbFocusTrap = (
	zone: NgZone,
	element: HTMLElement,
	stopFocusTrap$: Observable<any>,
	refocusOnClick = false,
) => {
	zone.runOutsideAngular(() => {
		// last focused element
		const lastFocusedElement$ = fromEvent<FocusEvent>(element, 'focusin').pipe(
			takeUntil(stopFocusTrap$),
			map((e) => e.target),
		);

		// 'tab' / 'shift+tab' stream
		fromEvent<KeyboardEvent>(element, 'keydown')
			.pipe(
				takeUntil(stopFocusTrap$),
				filter((e) => e.key === 'Tab'),
				withLatestFrom(lastFocusedElement$),
			)
			.subscribe(([tabEvent, focusedElement]) => {
				const [first, last] = getFocusableBoundaryElements(element);

				if ((focusedElement === first || focusedElement === element) && tabEvent.shiftKey) {
					last.focus();
					tabEvent.preventDefault();
				}

				if (focusedElement === last && !tabEvent.shiftKey) {
					first.focus();
					tabEvent.preventDefault();
				}
			});

		// inside click
		if (refocusOnClick) {
			fromEvent(element, 'click')
				.pipe(
					takeUntil(stopFocusTrap$),
					withLatestFrom(lastFocusedElement$),
					map((arr) => arr[1] as HTMLElement),
				)
				.subscribe((lastFocusedElement) => lastFocusedElement.focus());
		}
	});
};

function upsertOneMutably(entity: T, state: R): DidMutate;
  function upsertOneMutably(entity: any, state: any): DidMutate {
    return upsertManyMutably([entity], state);
  }

  function upsertManyMutably(entities: T[], state: R): DidMutate;
  function upsertManyMutably(entities: any[], state: any): DidMutate {
    const added: any[] = [];
    const updated: any[] = [];

    for (const entity of entities) {
      const id = selectIdValue(entity, selectId);
      if (id in state.entities) {
        updated.push({ id, changes: entity });
      } else {
        added.push(entity);
      }
    }

    const didMutateByUpdated = updateManyMutably(updated, state);
    const didMutateByAdded = addManyMutably(added, state);

    switch (true) {
      case didMutateByAdded === DidMutate.None &&
        didMutateByUpdated === DidMutate.None:
        return DidMutate.None;
      case didMutateByAdded === DidMutate.Both ||
        didMutateByUpdated === DidMutate.Both:
        return DidMutate.Both;
      default:
        return DidMutate.EntitiesOnly;
    }
  }

private initFieldOptions(field: FormlyFieldConfigCache) {
  reverseDeepMerge(field, {
    id: getFieldId(`formly_${this.formId}`, field, field.index),
    hooks: {},
    modelOptions: {},
    validation: { messages: {} },
    props:
      !field.type || !hasKey(field)
        ? {}
        : {
            label: '',
            placeholder: '',
            disabled: false,
          },
  });

  if (this.config.extras.resetFieldOnHide && field.resetOnHide !== false) {
    field.resetOnHide = true;
  }

  if (
    field.type !== 'formly-template' &&
    (field.template || field.expressions?.template || field.expressionProperties?.template)
  ) {
    field.type = 'formly-template';
  }

  if (!field.type && field.fieldGroup) {
    field.type = 'formly-group';
  }

  if (field.type) {
    this.config.getMergedField(field);
  }

  if (
    hasKey(field) &&
    !isUndefined(field.defaultValue) &&
    isUndefined(getFieldValue(field)) &&
    !isHiddenField(field)
  ) {
    assignFieldValue(field, field.defaultValue);
  }

  field.wrappers = field.wrappers || [];
}

private handleResult(field: FormlyFieldConfigCache, errors: any, { name, options }: ValidatorOption) {
  if (typeof errors === 'boolean') {
    errors = errors ? null : { [name]: options ? options : true };
  }

  const ctrl = field.formControl;
  ctrl?._childrenErrors?.[name]?.();

  if (isObject(errors)) {
    Object.keys(errors).forEach((name) => {
      const errorPath = errors[name].errorPath ? errors[name].errorPath : options?.errorPath;

      const childCtrl = errorPath ? field.formControl.get(errorPath) : null;
      if (childCtrl) {
        const { errorPath: _errorPath, ...opts } = errors[name];
        childCtrl.setErrors({ ...(childCtrl.errors || {}), [name]: opts });

        !ctrl._childrenErrors && defineHiddenProp(ctrl, '_childrenErrors', {});
        ctrl._childrenErrors[name] = () => {
          const { [name]: _toDelete, ...childErrors } = childCtrl.errors || {};
          childCtrl.setErrors(Object.keys(childErrors).length === 0 ? null : childErrors);
        };
      }
    });
  }

  return errors;
}

export function wrapI18nIcus(job: CompilationJob): void {
  for (const unit of job.units) {
    let currentI18nOp: ir.I18nStartOp | null = null;
    let addedI18nId: ir.XrefId | null = null;
    for (const op of unit.create) {
      switch (op.kind) {
        case ir.OpKind.I18nStart:
          currentI18nOp = op;
          break;
        case ir.OpKind.I18nEnd:
          currentI18nOp = null;
          break;
        case ir.OpKind.IcuStart:
          if (currentI18nOp === null) {
            addedI18nId = job.allocateXrefId();
            // ICU i18n start/end ops should not receive source spans.
            ir.OpList.insertBefore<ir.CreateOp>(
              ir.createI18nStartOp(addedI18nId, op.message, undefined, null),
              op,
            );
          }
          break;
        case ir.OpKind.IcuEnd:
          if (addedI18nId !== null) {
            ir.OpList.insertAfter<ir.CreateOp>(ir.createI18nEndOp(addedI18nId, null), op);
            addedI18nId = null;
          }
          break;
      }
    }
  }
}

export function consumeStyleValue(text: string, startIndex: number, endIndex: number): number {
  let ch1 = -1; // 1st previous character
  let ch2 = -1; // 2nd previous character
  let ch3 = -1; // 3rd previous character
  let i = startIndex;
  let lastChIndex = i;
  while (i < endIndex) {
    const ch: number = text.charCodeAt(i++);
    if (ch === CharCode.SEMI_COLON) {
      return lastChIndex;
    } else if (ch === CharCode.DOUBLE_QUOTE || ch === CharCode.SINGLE_QUOTE) {
      lastChIndex = i = consumeQuotedText(text, ch, i, endIndex);
    } else if (
      startIndex === i - 4 && // We have seen only 4 characters so far "URL(" (Ignore "foo_URL()")
      ch3 === CharCode.U &&
      ch2 === CharCode.R &&
      ch1 === CharCode.L &&
      ch === CharCode.OPEN_PAREN
    ) {
      lastChIndex = i = consumeQuotedText(text, CharCode.CLOSE_PAREN, i, endIndex);
    } else if (ch > CharCode.SPACE) {
      // if we have a non-whitespace character then capture its location
      lastChIndex = i;
    }
    ch3 = ch2;
    ch2 = ch1;
    ch1 = ch & CharCode.UPPER_CASE;
  }
  return lastChIndex;
}

function parseIcuCase(
  ast: I18nNode[],
  tView: TView,
  tIcu: TIcu,
  lView: LView,
  updateOpCodes: I18nUpdateOpCodes,
  parentIdx: number,
  caseName: string,
  unsafeCaseHtml: string,
  nestedIcus: IcuExpression[],
): number {
  const create: IcuCreateOpCodes = [] as any;
  const remove: I18nRemoveOpCodes = [] as any;
  const update: I18nUpdateOpCodes = [] as any;
  if (ngDevMode) {
    attachDebugGetter(create, icuCreateOpCodesToString);
    attachDebugGetter(remove, i18nRemoveOpCodesToString);
    attachDebugGetter(update, i18nUpdateOpCodesToString);
  }
  tIcu.cases.push(caseName);
  tIcu.create.push(create);
  tIcu.remove.push(remove);
  tIcu.update.push(update);

  const inertBodyHelper = getInertBodyHelper(getDocument());
  const inertBodyElement = inertBodyHelper.getInertBodyElement(unsafeCaseHtml);
  ngDevMode && assertDefined(inertBodyElement, 'Unable to generate inert body element');
  const inertRootNode = (getTemplateContent(inertBodyElement!) as Element) || inertBodyElement;
  if (inertRootNode) {
    return walkIcuTree(
      ast,
      tView,
      tIcu,
      lView,
      updateOpCodes,
      create,
      remove,
      update,
      inertRootNode,
      parentIdx,
      nestedIcus,
      0,
    );
  } else {
    return 0;
  }
}

function collectI18nChildren(tView: TView): Set<number> | null {
  const children = new Set<number>();

  function collectI18nViews(node: I18nNode) {
    children.add(node.index);

    switch (node.kind) {
      case I18nNodeKind.ELEMENT:
      case I18nNodeKind.PLACEHOLDER: {
        for (const childNode of node.children) {
          collectI18nViews(childNode);
        }
        break;
      }

      case I18nNodeKind.ICU: {
        for (const caseNodes of node.cases) {
          for (const caseNode of caseNodes) {
            collectI18nViews(caseNode);
          }
        }
        break;
      }
    }
  }

  // Traverse through the AST of each i18n block in the LView,
  // and collect every instruction index.
  for (let i = HEADER_OFFSET; i < tView.bindingStartIndex; i++) {
    const tI18n = tView.data[i] as TI18n | undefined;
    if (!tI18n || !tI18n.ast) {
      continue;
    }

    for (const node of tI18n.ast) {
      collectI18nViews(node);
    }
  }

  return children.size === 0 ? null : children;
}

