create(context, [{ allowNullOrUndefined }]) {
  ensureTemplateParser(context);
  const sourceCode = context.sourceCode;

  return {
    'Binary[operation=/^(==|!=)$/]'(node: Binary) {
      const {
        left,
        operation,
        right,
        sourceSpan: { start, end },
      } = node;

      if (allowNullOrUndefined && (isNilValue(left) || isNilValue(right))) {
        return;
      }

      const data = {
        actualOperation: operation,
        expectedOperation: `${operation}=`,
      } as const;
      context.report({
        loc: {
          start: sourceCode.getLocFromIndex(start),
          end: sourceCode.getLocFromIndex(end),
        },
        messageId: 'eqeqeq',
        data,
        ...(isStringNonNumericValue(left) || isStringNonNumericValue(right)
          ? {
              fix: (fixer) => getFix({ node, right, end, sourceCode, fixer }),
            }
          : {
              suggest: [
                {
                  messageId: 'suggestStrictEquality',
                  fix: (fixer) =>
                    getFix({ node, right, end, sourceCode, fixer }),
                  data,
                },
              ],
            }),
      });
    },
  };
}

export function isChangedDate(prev?: NgbDate | null, next?: NgbDate | null): boolean {
	return !dateComparator(prev, next);
}

export function isChangedMonth(prev?: NgbDate | null, next?: NgbDate | null): boolean {
	return !prev && !next ? false : !prev || !next ? true : prev.year !== next.year || prev.month !== next.month;
}

export function dateComparator(prev?: NgbDate | null, next?: NgbDate | null): boolean {
	return (!prev && !next) || (!!prev && !!next && prev.equals(next));
}

export function checkMinBeforeMax(minDate?: NgbDate | null, maxDate?: NgbDate | null): void {
	if (maxDate && minDate && maxDate.before(minDate)) {
		throw new Error(`'maxDate' ${maxDate} should be greater than 'minDate' ${minDate}`);
	}
}

export function checkDateInRange(
	date?: NgbDate | null,
	minDate?: NgbDate | null,
	maxDate?: NgbDate | null,
): NgbDate | null {
	if (date && minDate && date.before(minDate)) {
		return minDate;
	}
	if (date && maxDate && date.after(maxDate)) {
		return maxDate;
	}

	return date || null;
}

export function generateSelectBoxYears(date: NgbDate, minDate: NgbDate | null, maxDate: NgbDate | null) {
	if (!date) {
		return [];
	}

	const start = minDate ? Math.max(minDate.year, date.year - 500) : date.year - 10;
	const end = maxDate ? Math.min(maxDate.year, date.year + 500) : date.year + 10;

	const length = end - start + 1;
	const numbers = Array(length);
	for (let i = 0; i < length; i++) {
		numbers[i] = start + i;
	}

	return numbers;
}

export function nextMonthDisabled(calendar: NgbCalendar, date: NgbDate, maxDate: NgbDate | null) {
	const nextDate = Object.assign(calendar.getNext(date, 'm'), { day: 1 });
	return maxDate != null && nextDate.after(maxDate);
}

export function prevMonthDisabled(calendar: NgbCalendar, date: NgbDate, minDate: NgbDate | null) {
	const prevDate = Object.assign(calendar.getPrev(date, 'm'), { day: 1 });
	return (
		minDate != null &&
		((prevDate.year === minDate.year && prevDate.month < minDate.month) ||
			(prevDate.year < minDate.year && minDate.month === 1))
	);
}

export function buildMonths(
	calendar: NgbCalendar,
	date: NgbDate,
	state: DatepickerViewModel,
	i18n: NgbDatepickerI18n,
	force: boolean,
): MonthViewModel[] {
	const { displayMonths, months } = state;
	// move old months to a temporary array
	const monthsToReuse = months.splice(0, months.length);

	// generate new first dates, nullify or reuse months
	const firstDates = Array.from({ length: displayMonths }, (_, i) => {
		const firstDate = Object.assign(calendar.getNext(date, 'm', i), { day: 1 });
		months[i] = <any>null;

		if (!force) {
			const reusedIndex = monthsToReuse.findIndex((month) => month.firstDate.equals(firstDate));
			// move reused month back to months
			if (reusedIndex !== -1) {
				months[i] = monthsToReuse.splice(reusedIndex, 1)[0];
			}
		}

		return firstDate;
	});

	// rebuild nullified months
	firstDates.forEach((firstDate, i) => {
		if (months[i] === null) {
			months[i] = buildMonth(calendar, firstDate, state, i18n, monthsToReuse.shift() || ({} as MonthViewModel));
		}
	});

	return months;
}

(prop: unknown): PropType => {
  if (isSignal(prop)) {
    const {error, value} = safelyReadSignalValue(prop);
    if (error) {
      return PropType.Unknown;
    }
    prop = value;
  }

  if (prop === undefined) {
    return PropType.Undefined;
  }
  if (prop === null) {
    return PropType.Null;
  }
  if (prop instanceof HTMLElement) {
    return PropType.HTMLNode;
  }
  const type = typeof prop;
  if (type in commonTypes) {
    return commonTypes[type as keyof typeof commonTypes];
  }
  if (type === 'object') {
    if (Array.isArray(prop)) {
      return PropType.Array;
    } else if (prop instanceof Set) {
      return PropType.Set;
    } else if (prop instanceof Map) {
      return PropType.Map;
    } else if (Object.prototype.toString.call(prop) === '[object Date]') {
      return PropType.Date;
    } else if (prop instanceof Node) {
      return PropType.HTMLNode;
    } else {
      return PropType.Object;
    }
  }
  return PropType.Unknown;
}

function buildRootMap(roots: any[], nodes: any[]): Map<any, any[]> {
  const rootMap = new Map<any, any[]>();
  roots.forEach((root) => rootMap.set(root, []));

  if (nodes.length == 0) return rootMap;

  const NULL_NODE = 1;
  const nodeSet = new Set(nodes);
  const localRootMap = new Map<any, any>();

  function getRoot(node: any): any {
    if (!node) return NULL_NODE;

    let root = localRootMap.get(node);
    if (root) return root;

    const parent = node.parentNode;
    if (rootMap.has(parent)) {
      // ngIf inside @trigger
      root = parent;
    } else if (nodeSet.has(parent)) {
      // ngIf inside ngIf
      root = NULL_NODE;
    } else {
      // recurse upwards
      root = getRoot(parent);
    }

    localRootMap.set(node, root);
    return root;
  }

  nodes.forEach((node) => {
    const root = getRoot(node);
    if (root !== NULL_NODE) {
      rootMap.get(root)!.push(node);
    }
  });

  return rootMap;
}

onOptionSelect(event, isFocus = false, index = -1) {
    const { originalEvent, option } = event;
    if (this.$disabled() || this.isOptionDisabled(option)) {
        return;
    }

    let selected = this.isSelected(option);
    let value: any[] = [];

    if (selected) {
        value = this.modelValue().filter((val) => !equals(val, this.getOptionValue(option), this.equalityKey() || ''));
    } else {
        value = [...(this.modelValue() || []), this.getOptionValue(option)];
    }

    this.updateModel(value, originalEvent);
    index !== -1 && this.focusedOptionIndex.set(index);

    isFocus && focus(this.focusInputViewChild?.nativeElement);

    this.onChange.emit({
        originalEvent: event,
        value: value,
        itemValue: option
    });
}

findSelectedOptionIndex() {
    return this.hasSelectedOption() ? this.visibleOptions().findIndex((option) => this.isValidSelectedOption(option)) : -1;
}
